const TOKEN_KEY = 'trmdict_token';

export function getToken() {
    return localStorage.getItem(TOKEN_KEY);
}

export function setToken(token) {
    localStorage.setItem(TOKEN_KEY, token);
}

export function removeToken() {
    localStorage.removeItem(TOKEN_KEY);
}

export function parseToken(token) {
    try {
        const payload = token.split('.')[1];
        return JSON.parse(atob(payload));
    } catch {
        return null;
    }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { getToken, setToken, removeToken, parseToken } from './authUtils';

const TOKEN_KEY = 'trmdict_token';

describe('authUtils', () => {
    beforeEach(() => {
        localStorage.clear();
    });

    it('setToken — localStorage에 저장', () => {
        setToken('test-token');
        expect(localStorage.getItem(TOKEN_KEY)).toBe('test-token');
    });

    it('getToken — 저장된 토큰 반환', () => {
        localStorage.setItem(TOKEN_KEY, 'my-token');
        expect(getToken()).toBe('my-token');
    });

    it('removeToken — 토큰 삭제', () => {
        localStorage.setItem(TOKEN_KEY, 'my-token');
        removeToken();
        expect(localStorage.getItem(TOKEN_KEY)).toBeNull();
    });

    it('parseToken — 유효한 JWT payload 파싱', () => {
        // payload: { sub: '1', loginId: 'admin', role: 'ADMIN' }
        const payload = btoa(JSON.stringify({ sub: '1', loginId: 'admin', role: 'ADMIN' }));
        const fakeJwt = `header.${payload}.signature`;
        const result = parseToken(fakeJwt);
        expect(result.loginId).toBe('admin');
        expect(result.role).toBe('ADMIN');
    });
});

import { create } from 'zustand';

export const useAuthStore = create((set) => ({
    user: null,
    isAuthenticated: false,
    setUser: (user) => set({ user, isAuthenticated: !!user }),
    logout: () => set({ user: null, isAuthenticated: false }),
}));

import { describe, it, expect, beforeEach } from 'vitest';
import { act } from '@testing-library/react';
import { useAuthStore } from './useAuthStore';

describe('useAuthStore', () => {
    beforeEach(() => {
        act(() => {
            useAuthStore.getState().logout();
        });
    });

    it('초기 상태 — user null, isAuthenticated false', () => {
        const { user, isAuthenticated } = useAuthStore.getState();
        expect(user).toBeNull();
        expect(isAuthenticated).toBe(false);
    });

    it('setUser — user 설정 시 isAuthenticated true', () => {
        act(() => {
            useAuthStore.getState().setUser({ id: 1, loginId: 'admin', role: 'ADMIN' });
        });
        const { user, isAuthenticated } = useAuthStore.getState();
        expect(user.loginId).toBe('admin');
        expect(isAuthenticated).toBe(true);
    });

    it('logout — 상태 초기화', () => {
        act(() => {
            useAuthStore.getState().setUser({ id: 1, loginId: 'admin' });
            useAuthStore.getState().logout();
        });
        const { user, isAuthenticated } = useAuthStore.getState();
        expect(user).toBeNull();
        expect(isAuthenticated).toBe(false);
    });
});

import { create } from 'zustand';

export const useLoadingStore = create((set) => ({
    keys: new Set(),
    isLoading: false,
    start: (key) =>
        set((state) => {
            const next = new Set(state.keys);
            next.add(key);
            return { keys: next, isLoading: next.size > 0 };
        }),
    end: (key) =>
        set((state) => {
            const next = new Set(state.keys);
            next.delete(key);
            return { keys: next, isLoading: next.size > 0 };
        }),
}));

import { describe, it, expect, beforeEach } from 'vitest';
import { act } from '@testing-library/react';
import { useLoadingStore } from './useLoadingStore';

describe('useLoadingStore', () => {
    beforeEach(() => {
        act(() => {
            // 상태 초기화
            const { keys } = useLoadingStore.getState();
            keys.forEach((k) => useLoadingStore.getState().end(k));
        });
    });

    it('초기 상태 — isLoading false', () => {
        expect(useLoadingStore.getState().isLoading).toBe(false);
    });

    it('start — isLoading true', () => {
        act(() => useLoadingStore.getState().start('test'));
        expect(useLoadingStore.getState().isLoading).toBe(true);
    });

    it('end — 해당 키 제거 후 isLoading false', () => {
        act(() => {
            useLoadingStore.getState().start('test');
            useLoadingStore.getState().end('test');
        });
        expect(useLoadingStore.getState().isLoading).toBe(false);
    });

    it('복수 키 — 하나라도 남으면 isLoading true', () => {
        act(() => {
            useLoadingStore.getState().start('a');
            useLoadingStore.getState().start('b');
            useLoadingStore.getState().end('a');
        });
        expect(useLoadingStore.getState().isLoading).toBe(true);
    });

    it('복수 키 — 모두 end 시 isLoading false', () => {
        act(() => {
            useLoadingStore.getState().start('a');
            useLoadingStore.getState().start('b');
            useLoadingStore.getState().end('a');
            useLoadingStore.getState().end('b');
        });
        expect(useLoadingStore.getState().isLoading).toBe(false);
    });
});

