import axios from 'axios';
import { getToken, removeToken } from '../auth/authUtils';
import { useAuthStore } from '../../store/useAuthStore';

export const axiosInstance = axios.create({
    baseURL: '/api/v1',
    timeout: 30000,
    headers: {
        'Content-Type': 'application/json',
    },
});

axiosInstance.interceptors.request.use((config) => {
    const token = getToken();
    if (token) {
        config.headers['Authorization'] = `Bearer ${token}`;
    }
    return config;
});

axiosInstance.interceptors.response.use(
    (response) => response,
    (error) => {
        const status = error.response?.status;
        const code = error.response?.data?.code;

        if (status === 401 || code === 'AUTH_1002') {
            useAuthStore.getState().logout();
            removeToken();
        }

        return Promise.reject(error);
    }
);

import { describe, it, expect, vi, beforeEach } from 'vitest';
import MockAdapter from 'axios-mock-adapter';
import { axiosInstance } from './axiosInstance';
import * as authUtils from '../auth/authUtils';
import { useAuthStore } from '../../store/useAuthStore';

// npm install -D axios-mock-adapter
const mock = new MockAdapter(axiosInstance);

describe('axiosInstance interceptors', () => {
    beforeEach(() => {
        mock.reset();
        vi.restoreAllMocks();
        useAuthStore.getState().logout();
        authUtils.removeToken();
    });

    it('request — 토큰 있으면 Authorization 헤더 주입', async () => {
        authUtils.setToken('test-token');
        mock.onGet('/test').reply(200, {});
        const res = await axiosInstance.get('/test');
        expect(res.config.headers['Authorization']).toBe('Bearer test-token');
    });

    it('request — 토큰 없으면 Authorization 헤더 없음', async () => {
        mock.onGet('/test').reply(200, {});
        const res = await axiosInstance.get('/test');
        expect(res.config.headers['Authorization']).toBeUndefined();
    });

    it('response 401 — logout + token 제거', async () => {
        authUtils.setToken('expired-token');
        useAuthStore.getState().setUser({ id: 1, loginId: 'admin' });
        mock.onGet('/protected').reply(401, { code: 'AUTH_1002' });
        try {
            await axiosInstance.get('/protected');
        } catch {
            // expected
        }
        expect(authUtils.getToken()).toBeNull();
        expect(useAuthStore.getState().isAuthenticated).toBe(false);
    });

    it('response 403 — reject (toast는 컴포넌트 레이어에서 처리)', async () => {
        mock.onGet('/admin').reply(403, { code: 'COMMON_0003' });
        await expect(axiosInstance.get('/admin')).rejects.toThrow();
    });
});

